SELECT
      left_object.f1 AS f1,
      left_object.f1 AS f2
    FROM
      (
        SELECT
          DISTINCT f2 AS f1,
          f2 AS f2
        FROM
          t1
      ) AS left_object
      LEFT JOIN pk1 AS before ON (left_object.f1 = before.f1)
       JOIN LATERAL (
        SELECT
          f2 AS f1,
          f1 AS f2
        FROM
          t2
        LIMIT
          left_object.f1
      ) AS right_object ON (left_object.f2 = right_object.f1) ;

