SELECT
    (a1.f1) AS c1,
    (a2.f1) AS c2,
    (a1.f2) AS c3
FROM (
    SELECT
        a1.f2 AS f1,
        a1.f2 + a1.f1 AS f2
    FROM pk1 AS a1
    ORDER BY 1, 2
    LIMIT 1 OFFSET 1
) AS a1
LEFT JOIN (
    SELECT a1.f2 AS f1
    FROM t2 AS a1
    ORDER BY 1
    LIMIT 1 OFFSET 7
) AS a2
ON (a1.f2 != 4)
WHERE
    a2.f1 IS NULL
    AND a1.f1 + a1.f2 = NULLIF(a1.f1, a2.f1)
GROUP BY 1, 2, 3;

