WHERE
  event_type IN ('create', 'drop') AND
  object_type = 'cluster-replica' AND
  ((details->'cluster_name')::text LIKE '"c_schedule_%"' OR (details->'cluster_name')::text = '"other"') AND
  (details->'cluster_name')::text != '"c_schedule_4"';

