FROM lineitem
JOIN orders ON (l_orderkey = o_orderkey)
JOIN customer ON (o_custkey = c_custkey)
WHERE l_shipDATE BETWEEN '1995-04-19' AND '1995-11-14'
  AND c_acctbal <= 12907776
  AND c_acctbal >= l_extendedprice
GROUP BY 1,
         2
ORDER BY 1,
         2

